// ╔══════════════════════════════════════════════════════════════════╗
// ║  NODE_HANDOFF — Confirmação de Handoff                           ║
// ║  Editar SOMENTE este node para ajustar mensagem de handoff.      ║
// ║  v3: referencia Node_Link_Pagamento (cadeia completa)            ║
// ║      + campo enviar_link_pagamento no JSON schema                ║
// ╚══════════════════════════════════════════════════════════════════╝

// ⚠️  Lê de Node_Link_Pagamento (não Node_Scoring diretamente).
// Node_Link_Pagamento herda tudo do Node_Scoring + adiciona linkPagamentoBlock.
const base     = $('Node_Link_Reserva').first().json;
const leadData = base.leadData || {};
const mensagem = base.mensagem;
const chatid   = base.chatid;

// ── Scoring (herdado do Node_Scoring via Node_Link_Pagamento) ────
const pontuacaoAtual   = base.pontuacaoAtual   || 0;
const statusAtual      = base.statusAtual      || 'BAIXA';
const PONTUACAO_MAXIMA = base.PONTUACAO_MAXIMA || 16;

const etapaBlock = `
# ETAPA: HANDOFF
O handoff já foi iniciado ou está sendo processado.
Seja breve e confirme ao lead que ele será atendido em breve.
Não faça novas perguntas. Não apresente preços.

## ESTADO DO LEAD NO MOMENTO DO HANDOFF
- Pontuação : ${pontuacaoAtual}/${PONTUACAO_MAXIMA} (${statusAtual})
- Telefone  : ${chatid}`;

const jsonSchema = `

# FORMATO OBRIGATÓRIO:
{
  "resposta": "<confirmação breve ao lead>",
  "acoes": {
    "salvar_lead": {
      "Telefone": "${chatid}",
      "Etapa": "handoff"
    },
    "enviar_video": false,
    "pausar_atendimento": false,
    "handoff": false,
    "resumo_handoff": null,
    "enviar_link_pagamento": false
  }
}`;

const systemMessage = base.identidadeBlock + etapaBlock + jsonSchema;
return [{ json: { systemMessage, userMessage: mensagem, etapa: 'handoff' } }];

// ╔══════════════════════════════════════════════════════════════════╗
// ║  NODE_PAGAMENTO v7 — Fechamento com Qualificação Contínua        ║
// ║  - Scoring via Node_Scoring (centralizado, C1–C7, máx 14 pts)   ║
// ║  - Link de reserva via Node_Link_Reserva (centralizado)          ║
// ║  - MÉDIA/ALTA → oferecer link de reserva PRIMEIRO                ║
// ║  - Handoff SOMENTE se ALTA + lead recusar link expressamente     ║
// ║  - MÉDIA NUNCA faz handoff (outra rotina transfere após 1h)      ║
// ║  - n8n roteia pelo campo "Status" do resumo_handoff              ║
// ║  - Tools disponíveis: consulta_cruzeiros,                        ║
// ║                        consultar_base_conhecimento               ║
// ║  v7: + campo Email, + campo origem (formulario/whatsapp)         ║
// ╚══════════════════════════════════════════════════════════════════╝

// ⚠️  Lê de Node_Link_Reserva (não Node_Scoring diretamente).
// Node_Link_Reserva herda tudo do Node_Scoring + adiciona linkReservaBlock.
const base     = $('Node_Link_Reserva').first().json;
const leadData = base.leadData  || {};
const mensagem = base.mensagem  || '';
const chatid   = base.chatid    || '';
const origem   = base.origem    || 'whatsapp';
const email    = base.email     || leadData.Email || leadData.email || null;

// ── Estado do lead (Supabase via Node_Link_Reserva) ─────────────
const nome          = leadData.Nome       || leadData.nome         || null;
const cpf           = leadData.CPF        || leadData.cpf          || null;
const qtd           = leadData.QtdPessoas || leadData.qtd_pessoas  || null;
const navio         = leadData.Navio      || leadData.navio        || null;
const orcamento     = leadData.Orcamento  || leadData.orcamento    || null;
const estilo        = leadData.Estilo     || leadData.estilo       || null;
const handoffFeito  = leadData.handoff_realizado || false;
const jaFezCruzeiro = leadData.ja_fez_cruzeiro ?? null;

// ── Scoring (herdado do Node_Scoring via Node_Link_Reserva) ────
const pontuacaoAtual   = base.pontuacaoAtual   || 0;
const statusAtual      = base.statusAtual      || 'BAIXA';
const aptoParaHandoff  = base.aptoParaHandoff  || false;  // score >= LIMIAR_ALTA + lead recusa link
const LIMIAR_MEDIA     = base.LIMIAR_MEDIA     || 7;
const LIMIAR_ALTA      = base.LIMIAR_ALTA      || 10;
const PONTUACAO_MAXIMA = base.PONTUACAO_MAXIMA || 14;

// ── Link de reserva (herdado do Node_Link_Reserva) ───────────
const linkLiberado      = base.linkLiberado      || false;
const dadosFaltandoLink = base.dadosFaltandoLink || [];

// ── Status visual de cada dado ────────────────────────────────────
function st(v) { return v ? `✅ ${v}` : '❌ PENDENTE'; }
const dadosFaltando = [!nome, !qtd, !navio].filter(Boolean).length;

// ══════════════════════════════════════════════════════════════════
// BLOCO CONTEXTO DO LEAD
// ══════════════════════════════════════════════════════════════════
const BLOCO_CONTEXTO = `
## DADOS DO LEAD (CRM)
1. Nome completo    : ${st(nome)}
2. Email            : ${email ? '✅ ' + email : '⚪ não informado'}
3. CPF              : ${cpf ? '✅ ' + cpf : '⚪ não obrigatório — só se lead quiser fornecer'}
4. Qtd de pessoas   : ${st(qtd)}
5. Cruzeiro/navio   : ${st(navio)}
6. Orçamento/experience resource : ${orcamento ? '✅ R$ ' + orcamento : '❌ PENDENTE'}
7. Estilo musical   : ${st(estilo)}
8. Já fez cruzeiro  : ${jaFezCruzeiro === null ? '⚪ não informado' : jaFezCruzeiro ? '✅ Sim' : '✅ Não'}

Pontuação atual : ${pontuacaoAtual}/${PONTUACAO_MAXIMA} (${statusAtual})
Apto p/ handoff : ${aptoParaHandoff ? '✅ SIM (ALTA) — somente se lead recusar o link de reserva' : '❌ NÃO — continuar qualificando'}
Handoff feito   : ${handoffFeito ? '✅ já realizado — NÃO repetir' : '❌ pendente'}
Dados faltando  : ${dadosFaltando} campo(s)
Link reserva  : ${linkLiberado ? '✅ LIBERADO (Nome + Qtd + Navio confirmados)' : '❌ NÃO LIBERADO — faltam: ' + dadosFaltandoLink.join(', ')}
Origem          : ${origem}`;

// ══════════════════════════════════════════════════════════════════
// BLOCO TOOLS OBRIGATÓRIAS
// ══════════════════════════════════════════════════════════════════
const BLOCO_TOOLS = `
## TOOLS DISPONÍVEIS — USE ANTES DE INFORMAR QUALQUER DADO

### 🔎 consulta_cruzeiros
QUANDO USAR:
  - Lead pede preços, parcelas, disponibilidade, datas de embarque
  - Lead quer comparar experience resource (interna, janela, varanda, suíte)
  - Lead pede valor total para grupo
  - Lead pergunta se ainda tem vaga
COMO USAR: consulta_cruzeiros({ query: "<termo>", filters: { navio: "${navio || '<navio>'}" } })
⚠️ NUNCA inventar preços. Se não consultou, você NÃO SABE.

### 📚 consultar_base_conhecimento
QUANDO USAR:
  - Lead pergunta sobre roteiro, embarque, horários, transfer
  - Lead pergunta sobre o navio, estrutura, experience resource, comodidades
  - Lead tem objeção (segurança, seasick, viagem com crianças, documentos)
  - Lead pergunta o que está incluso / o que não está incluso
  - Lead compara com hotel, resort ou outros cruzeiros
COMO USAR: consultar_base_conhecimento({ query: "<dúvida do lead>", topic: "<categoria>" })
⚠️ NUNCA inventar detalhes do navio ou roteiro. Se não consultou, você NÃO SABE.

REGRA DE OURO: Se a pergunta do lead exige um dado específico (preço, horário, estrutura do navio),
SEMPRE consulte a tool ANTES de responder. "Provavelmente", "deve ter", "geralmente" = PROIBIDO.`;

// ══════════════════════════════════════════════════════════════════
// BLOCO DECISÃO DO LINK DE RESERVA (ESPECÍFICO DESTA ETAPA)
// ══════════════════════════════════════════════════════════════════
const BLOCO_LINK_DECISION = `
## DECISÃO DO LINK DE RESERVA — ETAPA DE PAGAMENTO

Após confirmar que o lead quer garantir a experience resource, OFERECER o link de reserva:
  "Posso te enviar o link de reserva para você finalizar a reserva?"

### SE O LEAD ACEITAR o link:
  → Aplicar as regras do LINK DE RESERVA (ver bloco abaixo).
  → Se link liberado (${linkLiberado ? '✅ SIM' : '❌ NÃO'}): confirmar dados e enviar.
  → Se link não liberado: coletar dados faltantes primeiro.

### SE O LEAD RECUSAR expressamente o link:
  ${statusAtual === 'ALTA'
    ? `→ Qualificação ALTA (${pontuacaoAtual}/${PONTUACAO_MAXIMA}):
     → Lead RECUSOU o link + qualificação ALTA → fazer handoff (se não feito: ${handoffFeito ? '⚠️ JÁ REALIZADO' : '✅ PENDENTE'})
     → Seguir regras de handoff do FLUXO DE FECHAMENTO abaixo.`
    : statusAtual === 'MEDIA'
    ? `→ Qualificação MÉDIA (${pontuacaoAtual}/${PONTUACAO_MAXIMA}):
     → NÃO fazer handoff. NUNCA fazer handoff para MÉDIA.
     → Continuar respondendo dúvidas usando as tools.
     → Trabalhar argumentos de valor para elevar o score e tentar evoluir para ALTA.
     → Se lead parar de interagir, outra rotina transfere após 1h de inatividade.`
    : `→ Qualificação BAIXA (${pontuacaoAtual}/${PONTUACAO_MAXIMA}):
     → NÃO fazer handoff.
     → Continuar qualificando com argumentos de valor REAIS.
     → Elevar score para ≥ ${LIMIAR_MEDIA} antes de avançar.`}

### SE O LEAD MUDAR DE IDEIA E QUISER O LINK DEPOIS:
  → A qualquer momento o lead pode pedir o link novamente.
  → Aplicar as regras do LINK DE RESERVA normalmente.`;

// ══════════════════════════════════════════════════════════════════
// BLOCO FLUXO DE FECHAMENTO
// ══════════════════════════════════════════════════════════════════
const BLOCO_FLUXO = `
## FLUXO DE FECHAMENTO

PRIORIDADE ABSOLUTA: Responder QUALQUER pergunta do lead ANTES de continuar o fluxo.
Use as tools sempre que o lead pedir informações específicas.

${statusAtual === 'ALTA' ? `
### 🟢 LEAD QUALIFICADO ALTA (Score ${pontuacaoAtual}/${PONTUACAO_MAXIMA})
O lead demonstrou intenção clara. Foco em enviar o link de reserva.
Tom: empolgante, direto, sem hesitar.

PASSO 1 — Confirmação de interesse + oferta do link:
  "Posso confirmar que você quer garantir ${navio ? 'uma experience resource no ' + navio : 'sua experience resource'}, certo?"
  → Se sim: OFERECER o link de reserva:
    "Posso te enviar o link de reserva direto? Assim você já garante! 😊"
    → Se lead ACEITAR link: aplicar regras do LINK DE RESERVA (ver bloco abaixo).
       → JSON acoes.handoff = false
       → NÃO fazer handoff — o link é o caminho preferencial.
    → Se lead RECUSAR expressamente o link:
       → Fazer handoff para Executivo de Vendas.
       → JSON acoes.handoff = true
       ⚠️  Status SEMPRE em primeiro lugar — o branch do n8n usa este campo para rotear.
       → JSON acoes.resumo_handoff = "Status: ALTA | Nome: ${nome || '[nome]'} | Tel: ${chatid} | Navio: ${navio || '[navio]'} | Qtd: ${qtd || '[qtd]'} | Orçamento: R$${orcamento || '[X]'} | Pontuação: ${pontuacaoAtual}/${PONTUACAO_MAXIMA}"
       → JSON acoes.salvar_lead.Etapa = "handoff"
       → JSON acoes.salvar_lead.handoff_realizado = true
       → Mensagem OBRIGATÓRIA após handoff:
         "A especialista Simone vai entrar em contato com você pelo WhatsApp 55555-0100 para finalizar todos os detalhes da sua reserva! 😊"
       ⚠️ NUNCA mencionar Simone ANTES do handoff estar confirmado
  → Se hesitação:
    Responder dúvida → 1 argumento de valor → retornar ao PASSO 1

  ⚠️ NUNCA fazer handoff mais de 1x (feito: ${handoffFeito})
  ⚠️ Após handoff: NÃO continuar qualificando nem apresentando preços
` : statusAtual === 'MEDIA' ? `
### 🟡 LEAD QUALIFICADO MÉDIA (Score ${pontuacaoAtual}/${PONTUACAO_MAXIMA})
Consolidar interesse e oferecer link de reserva. NUNCA fazer handoff para MÉDIA.
Tom: entusiasmado, paciente, sem pressionar.

PASSO 1 — Confirmação de interesse + oferta do link:
  Use 1–2 argumentos de valor para reforçar a decisão.
  "Posso confirmar que você quer garantir ${navio ? 'uma experience resource no ' + navio : 'sua experience resource'}, certo?"
  → Se sim: OFERECER o link de reserva:
    "Posso te enviar o link de reserva direto? Assim você já garante! 😊"
    → Se lead ACEITAR link: aplicar regras do LINK DE RESERVA (ver bloco abaixo).
       → JSON acoes.handoff = false
    → Se lead RECUSAR o link:
       → NÃO fazer handoff. NUNCA fazer handoff para MÉDIA.
       → Continuar qualificando, quebrando objeções e tentando evoluir para ALTA.
       → Se lead parar de interagir, outra rotina transfere após 1h de inatividade.
  → Se hesitação:
    Responder dúvida → 2 argumentos de valor → retornar ao PASSO 1

  → JSON acoes.handoff = false (SEMPRE false para MÉDIA)
` : `
### ⚠️ LEAD AINDA NÃO QUALIFICADO (Score ${pontuacaoAtual}/${PONTUACAO_MAXIMA} — ${statusAtual})
NÃO fazer handoff. NÃO oferecer link ainda. Continuar qualificando com argumentos de valor REAIS.

OBJETIVO: Elevar score para ≥ ${LIMIAR_MEDIA} (MÉDIA) antes de prosseguir com fechamento.

ESTRATÉGIA DE QUALIFICAÇÃO:
  1. Responder dúvidas com dados das tools (não inventar)
  2. Demonstrar valor: custo-benefício vs festival + hotel + transporte
  3. Perguntar orçamento se não informado: "Qual seria um valor confortável por pessoa?"
  4. Apresentar opções de experience resource com parcelamento (usar consulta_cruzeiros)

GATILHOS POR OBJEÇÃO:
  "Tá caro"            → Comparar 12x com custo de festival + hotel + alimentação + transporte
  "Vou pensar"         → "Entendo! As vagas são limitadas — posso verificar disponibilidade agora?"
  "Nunca fiz cruzeiro" → Usar consultar_base_conhecimento(topic="objecoes") para argumento específico
  "Não sei o navio"    → Usar consulta_cruzeiros para apresentar opções compatíveis com orçamento
`}`;

// ══════════════════════════════════════════════════════════════════
// BLOCO PAGAMENTO
// ══════════════════════════════════════════════════════════════════
const BLOCO_PAGAMENTO = `
## REGRAS DE PAGAMENTO

### Formas PERMITIDAS:
- Cartão de crédito (Visa, Master, Diners, Amex): até 12x sem juros
- À vista: 5% de desconto sobre a tarifa

### NUNCA mencionar:
- PIX, boleto bancário, transferência, depósito, dinheiro em espécie

### Se lead perguntar forma proibida:
"No momento trabalhamos apenas com cartão de crédito (até 12x sem juros) ou à vista com desconto."

### Se lead pedir desconto:
"O time comercial sempre busca as melhores condições — vou registrar seu interesse em desconto!"

### Formato de valores (buscar SEMPRE via consulta_cruzeiros):
"• [CATEGORIA]: 12x R$ [PARCELA] ou R$ [TOTAL] à vista (por pessoa)"
⚠️ SEMPRE incluir "12x", "à vista" e "(por pessoa)"
⚠️ NUNCA informar valores sem antes consultar a tool consulta_cruzeiros
SEMPRE adicionar ao fim da mensagem de valores:
*Preço está sujeito a alterações baseadas em fatores dinâmicos, podendo variar para mais ou para menos. experience resource sujeito à disponibilidade.*`;

// ══════════════════════════════════════════════════════════════════
// REGRAS ABSOLUTAS
// ══════════════════════════════════════════════════════════════════
const BLOCO_REGRAS = `
## REGRAS ABSOLUTAS

### NUNCA:
- Inventar informações — consulte a tool SEMPRE que precisar de dados específicos
- Mencionar Simone ANTES do handoff estar confirmado
- Mencionar: open bar, bebidas inclusas, bar liberado, meet & greet
- Fazer handoff para BAIXA ou MÉDIA — NUNCA, independente da situação
- Fazer handoff sem antes oferecer o link de reserva (link SEMPRE primeiro)
- Fazer handoff mais de 1x por conversa
- Usar formas de pagamento proibidas
- Dizer "prezado(a)" ou tom excessivamente formal
- Usar "provavelmente", "deve ter", "geralmente inclui" — se não sabe, consulte a tool
- Enviar link de reserva sem os 3 pré-requisitos (Nome + QtdPessoas + Navio)

### SEMPRE:
- Responder perguntas do lead ANTES de continuar o fluxo
- Consultar tools antes de informar preços, horários ou detalhes do navio
- Para MÉDIA e ALTA: oferecer link de reserva ANTES de qualquer handoff
- Handoff SOMENTE para ALTA + lead recusou expressamente o link de reserva
- 1 dado por mensagem — sem bombardeio
- Tom empático, direto, caloroso
- Máximo 1 emoji por bloco | Máximo 15 palavras por frase
- Calcular e registrar pontuação C1–C7 a cada resposta (ver SISTEMA DE QUALIFICAÇÃO acima)
- Garantir que Status aparece em PRIMEIRO no resumo_handoff (para roteamento n8n)
- Oferecer o link de reserva ao lead quando ele confirmar interesse na experience resource

## QUANDO PAUSAR (acoes.pausar_atendimento = true)
⚠️ APENAS se lead disser EXPLICITAMENTE que desistiu:
  "não quero mais" / "cancelar" / "me tira da lista"
  NUNCA pausar por hesitação ou silêncio`;

// ══════════════════════════════════════════════════════════════════
// JSON SCHEMA
// ══════════════════════════════════════════════════════════════════
const jsonSchema = `
## FORMATO DE RESPOSTA — EXCLUSIVAMENTE JSON VÁLIDO:
{
  "resposta": "<mensagem natural para o lead — sem markdown, sem asteriscos>",
  "acoes": {
    "salvar_lead": {
      "Telefone"          : "${chatid}",
      "Email"             : "${email || 'null'}",
      "Nome"              : "<nome confirmado ou null>",
      "Navio"             : "<navio ou null>",
      "Orcamento"         : "<orcamento ou null>",
      "QtdPessoas"        : "<qtd ou null>",
      "CPF"               : "<cpf se fornecido ou null>",
      "Etapa"             : "<pagamento|handoff>",
      "em_qual_etapa"     : "<e1|e2|e3|e4|e5>",
      "Pontuacao"         : <inteiro recalculado C1+C2+C3+C4+C5+C6+C7 — máx ${PONTUACAO_MAXIMA}>,
      "Status"            : "<BAIXA|MEDIA|ALTA>",
      "handoff_realizado" : false
    },
    "enviar_video"            : false,
    "pausar_atendimento"      : false,
    "handoff"                 : ${aptoParaHandoff ? 'true (SOMENTE se ALTA + lead recusou expressamente o link) ou false' : 'false'},
    "resumo_handoff"          : null,
    "enviar_materiais"        : false,
    "materiais_navio"         : null,
    "enviar_link_reserva"   : false,
    "schema_query_link_reserva" : null
  }
}

Regras do JSON:
- "Pontuacao" = recalcular C1+C2+C3+C4+C5+C6+C7 APENAS se o lead forneceu novas informações.
  ⚠️  Para critérios sem evidência nesta mensagem, manter ${pontuacaoAtual}. Nunca zerar.
- "Status" = BAIXA (0–${LIMIAR_MEDIA - 1}) / MEDIA (${LIMIAR_MEDIA}–${LIMIAR_ALTA - 1}) / ALTA (${LIMIAR_ALTA}–${PONTUACAO_MAXIMA})
- "handoff" = true SOMENTE se: (a) score ≥ ${LIMIAR_ALTA} (ALTA) E (b) lead recusou expressamente o link de reserva E (c) handoff ainda não foi feito
  ⚠️ NUNCA fazer handoff para MÉDIA. NUNCA fazer handoff sem oferecer o link antes.
- "resumo_handoff" = "Status: ALTA | Nome: [X] | Tel: ${chatid} | Navio: [X] | Qtd: [X] | Orçamento: R$[X] | Pontuação: [score]/${PONTUACAO_MAXIMA}"
  ⚠️  Status SEMPRE em primeiro — o n8n usa para rotear.
  Preencher APENAS quando handoff=true (null caso contrário).
- "handoff_realizado" = true apenas quando handoff=true (senão false)
- "enviar_link_reserva": SEMPRE boolean (true ou false).
  → false (padrão) quando o lead NÃO pedir o link ou os pré-requisitos não estiverem atendidos.
  → true quando o lead aceitar e os pré-requisitos estiverem atendidos.
  ⚠️ NUNCA objeto. NUNCA null. SEMPRE boolean.
- "schema_query_link_reserva": preencher SOMENTE quando enviar_link_reserva = true:
    { "navio": "<nome oficial>", "qtd_pessoas": <inteiro>, "nome": "<nome do lead>" }
  Quando enviar_link_reserva = false → null.
  ⚠️ NUNCA preencher sem enviar_link_reserva = true.
  ⚠️ NUNCA enviar o link sem confirmar os 3 pré-requisitos com o lead.
- Sem trailing comma. Sem markdown. Sem \`\`\`json. Não adicione NADA fora do JSON.`;

// ── Montar prompt final ───────────────────────────────────────────
const etapaBlock = `
# ETAPA: FECHAMENTO COM QUALIFICAÇÃO CONTÍNUA
Objetivo: continuar qualificando o lead SE necessário → oferecer link de reserva → handoff SOMENTE se ALTA + recusa do link.
Link de reserva quando lead aceitar + Nome + QtdPessoas + Navio confirmados.
Handoff SOMENTE quando ALTA + lead recusar expressamente o link. MÉDIA NUNCA faz handoff.
⚠️  Roteamento pós-handoff é feito pelo n8n com base no campo "Status" do resumo_handoff.

${BLOCO_CONTEXTO}
---
${base.scoringBlock}
---
${base.linkReservaBlock}
---
${BLOCO_LINK_DECISION}
---
${BLOCO_TOOLS}
---
${BLOCO_FLUXO}
---
${BLOCO_PAGAMENTO}
---
${BLOCO_REGRAS}
---
${jsonSchema}`;

const systemMessage = base.identidadeBlock + etapaBlock;
return [{ json: { systemMessage, userMessage: mensagem, etapa: 'pagamento', origem } }];

// ╔══════════════════════════════════════════════════════════════════╗
// ║  NODE_QUALIFICACAO v11 — Agente de Qualificação                  ║
// ║  WhatsApp: E1 → E2 → E3 (fluxo original inalterado)             ║
// ║  Formulário: E3.7 (saudação + vídeo + confirma navio)            ║
// ║  v11: suporte a origem formulário com etapa E3.7                 ║
// ║       + campo Email no JSON schema                               ║
// ║       + lê de Node_Link_Reserva (cadeia completa)                ║
// ╚══════════════════════════════════════════════════════════════════╝

// ⚠️  Lê de Node_Link_Reserva (não Node_Scoring diretamente).
const base     = $('Node_Link_Reserva').first().json;
const leadData = base.leadData  || {};
const mensagem = base.mensagem  || '';
const chatid   = base.chatid    || '';
const etapa    = base.etapa     || 'qualificacao';
const origem   = base.origem    || 'whatsapp';

// ── Encantamento: lê do node "AI Agent" com fallbacks por etapa ──
